      expect(SAMPLE_RESPONSE.locale).toBe('en-IN'); // FAILS: actual is "en"
    });

  });

  // ── 4. Timestamps — Local Time Validation ────────────

  describe('4. Timestamps — Must be in user local time (IST +05:30), not UTC', () => {

