  1	import { Page, Locator, expect } from '@playwright/test';
  2	
  3	/**
  4	 * Page Object Model for the Autocomplete Form.
  5	 * URL: https://test.com/autocomplete-form
  6	 *
  7	 * Encapsulates all selectors and interaction methods so that
  8	 * test scripts stay readable and easy to maintain.
  9	 */
 10	export class AutocompleteFormPage {
 11	  readonly page: Page;
 12	
 13	  // Element locators
 14	  readonly inputField: Locator;
 15	  readonly suggestionList: Locator;
 16	  readonly suggestionItems: Locator;
 17	  readonly nextButton: Locator;
 18	  readonly errorMessage: Locator;
 19	  readonly successContainer: Locator;
 20	
 21	  constructor(page: Page) {
 22	    this.page = page;
 23	    this.inputField      = page.locator('#input-field');
 24	    this.suggestionList  = page.locator('ul.suggestions');
 25	    this.suggestionItems = page.locator('ul.suggestions li');
 26	    this.nextButton      = page.locator('#next-button');
 27	    this.errorMessage    = page.locator('span.error-message');
 28	    this.successContainer = page.locator('div.success-container');
 29	  }
 30	
 31	  /** Navigate to the autocomplete form page. */
 32	  async goto() {
 33	    await this.page.goto('/autocomplete-form');
 34	  }
 35	
 36	  /** Type text into the input field to trigger suggestion filtering. */
 37	  async typeInInput(text: string) {
 38	    await this.inputField.click();
 39	    await this.inputField.fill(text);
 40	  }
 41	
 42	  /** Clear the input field using the Escape key. */
 43	  async clearWithEscape() {
 44	    await this.inputField.focus();
 45	    await this.page.keyboard.press('Escape');
 46	  }
 47	
 48	  /** Click a suggestion item by its exact visible text. */
 49	  async selectSuggestion(text: string) {
 50	    await this.suggestionList.locator(`li:has-text("${text}")`).click();
 51	  }
 52	
 53	  /** Click the Next button to submit the form. */
 54	  async clickNext() {
 55	    await this.nextButton.click();
 56	  }
 57	
 58	  /** Returns an array of all currently visible suggestion texts. */
 59	  async getVisibleSuggestions(): Promise<string[]> {
 60	    const items = await this.suggestionItems.all();
 61	    const texts: string[] = [];
 62	    for (const item of items) {
 63	      if (await item.isVisible()) {
 64	        texts.push((await item.innerText()).trim());
 65	      }
 66	    }
 67	    return texts;
 68	  }
 69	
 70	  /** Assert the error message element is visible. */
 71	  async assertErrorVisible() {
 72	    await expect(this.errorMessage).toBeVisible();
 73	  }
 74	
 75	  /** Assert the success container is visible. */
 76	  async assertSuccessVisible() {
 77	    await expect(this.successContainer).toBeVisible();
 78	  }
 79	
 80	  /** Assert the error message element is hidden. */
 81	  async assertErrorHidden() {
 82	    await expect(this.errorMessage).toBeHidden();
 83	  }
 84	
 85	  /** Assert the success container is hidden. */
 86	  async assertSuccessHidden() {
 87	    await expect(this.successContainer).toBeHidden();
 88	  }
 89	
 90	  /** Assert the input field has a specific value. */
 91	  async assertInputValue(expected: string) {
 92	    await expect(this.inputField).toHaveValue(expected);
 93	  }
 94	
 95	  /** Assert the exact list of visible suggestions. */
 96	  async assertVisibleSuggestions(expected: string[]) {
 97	    const visible = await this.getVisibleSuggestions();
 98	    expect(visible).toEqual(expected);
 99	  }
100	}
