```ts
// Line 1 — Import Playwright tools
import { Page, Locator, expect } from '@playwright/test';
// Page = the browser tab
// Locator = a way to find HTML elements
// expect = for writing assertions (checking things are correct)

// Line 10 — Create the class
export class AutocompleteFormPage {

  // Lines 11-19 — Declare variables for each element on the page
  readonly page: Page;            // The browser tab itself
  readonly inputField: Locator;   // The <input id="input-field"> element
  readonly suggestionList: Locator;  // The <ul class="suggestions"> element
  readonly suggestionItems: Locator; // All <li> inside the suggestions list
  readonly nextButton: Locator;      // The <button id="next-button">
  readonly errorMessage: Locator;    // The <span class="error-message">
  readonly successContainer: Locator;// The <div class="success-container">

  // Lines 21-29 — Constructor: runs when you do "new AutocompleteFormPage(page)"
  constructor(page: Page) {
    this.page = page;
    // page.locator() finds elements using CSS selectors — same as DevTools
    this.inputField = page.locator('#input-field');       // finds by ID
    this.suggestionList = page.locator('ul.suggestions'); // finds by tag + class
    this.suggestionItems = page.locator('ul.suggestions li'); // finds all <li> inside
    this.nextButton = page.locator('#next-button');
    this.errorMessage = page.locator('span.error-message');
    this.successContainer = page.locator('div.success-container');
  }

  // goto() — Navigate the browser to the form page
  async goto() {
    await this.page.goto('/autocomplete-form');
    // 'await' means: wait for this to finish before moving to next line
    // async means: this function can pause and wait
  }

  // typeInInput() — Click the input box and type text into it
  async typeInInput(text: string) {
    await this.inputField.click();  // Click first to focus it
    await this.inputField.fill(text); // Then type the text
  }

  // clearWithEscape() — Press Escape to clear the field
  async clearWithEscape() {
    await this.inputField.focus();
    await this.page.keyboard.press('Escape');
  }

  // selectSuggestion() — Click a specific suggestion by its text
  async selectSuggestion(text: string) {
    // li:has-text("...") finds the <li> that contains that exact text
    await this.suggestionList.locator(`li:has-text("${text}")`).click();
  }

  // clickNext() — Click the Next button
  async clickNext() {
    await this.nextButton.click();
  }

  // getVisibleSuggestions() — Returns list of suggestions currently visible
  async getVisibleSuggestions(): Promise<string[]> {
    const items = await this.suggestionItems.all(); // Get all <li> elements
    const texts: string[] = [];                      // Empty array to fill
    for (const item of items) {                      // Loop through each <li>
      if (await item.isVisible()) {                  // Only include visible ones
        texts.push((await item.innerText()).trim());  // Add text to array
      }
    }
    return texts; // Return the array of visible suggestion texts
  }

  // Assertion methods — each checks something specific about the page
  async assertErrorVisible() {
    await expect(this.errorMessage).toBeVisible(); // FAIL if error is hidden
  }
  async assertSuccessVisible() {
    await expect(this.successContainer).toBeVisible(); // FAIL if success hidden
  }
  async assertErrorHidden() {
    await expect(this.errorMessage).toBeHidden(); // FAIL if error is showing
  }
  async assertSuccessHidden() {
    await expect(this.successContainer).toBeHidden();
  }
  async assertInputValue(expected: string) {
    await expect(this.inputField).toHaveValue(expected); // FAIL if wrong value
  }
  async assertVisibleSuggestions(expected: string[]) {
    const visible = await this.getVisibleSuggestions();
    expect(visible).toEqual(expected); // FAIL if list doesn't match exactly
  }
}
```

