  test('TC-SUBMIT-01 | Valid suggestion + Next shows success message', async () => {
    await formPage.selectSuggestion('agile methodology');
    await formPage.clickNext();
    await formPage.assertSuccessVisible(); // Green success message should appear
    await formPage.assertErrorHidden();    // Red error should stay hidden
  });

