    await formPage.typeInInput('random invalid text'); // Type something invalid
    await formPage.clickNext();
    await formPage.assertErrorVisible();   // Error should appear
    await formPage.assertSuccessHidden();  // Success should stay hidden
  });

  // ── KEYBOARD TESTS ──
  test('TC-TAB-01 | Tab moves focus to first suggestion item', async ({ page }) => {
    await formPage.inputField.focus();    // Start at the input field
    await page.keyboard.press('Tab');     // Press Tab once
    const firstSuggestion = formPage.suggestionItems.first();
    await expect(firstSuggestion).toBeFocused(); // First <li> should be focused
  });

  test('TC-KEY-03 | Escape clears input and restores all suggestions', async ({ page }) => {
    await formPage.typeInInput('agile meth'); // Type something to filter
    await page.keyboard.press('Escape');       // Press Escape
    await formPage.assertInputValue('');        // Input should now be empty
    await formPage.assertVisibleSuggestions([  // All 3 should be back
      'agile methodology',
      'agile methodology process',
      'agile methodology process testing',
    ]);
  });

  // ── FULL KEYBOARD FLOW ──
  test('TC-KEY-04 | Full keyboard-only flow completes and submits', async ({ page }) => {
    await formPage.inputField.focus();
    await page.keyboard.type('agile');    // Type in the field
    await page.keyboard.press('Tab');     // Tab to first suggestion
    await page.keyboard.press('Enter');   // Select it with Enter
    await formPage.assertInputValue('agile methodology'); // Verify selected

    // Keep pressing Tab until the Next button is focused
    let attempts = 0;
    while (attempts < 5) {
      const focused = await page.evaluate(() => document.activeElement?.id);
      // page.evaluate() runs JavaScript directly in the browser
      // document.activeElement = whichever element currently has focus
      if (focused === 'next-button') break; // Stop when Next button is focused
      await page.keyboard.press('Tab');
      attempts++; // Safety limit — max 5 tabs to avoid infinite loop
    }

    await page.keyboard.press('Enter'); // Submit the form
    await formPage.assertSuccessVisible(); // Should show success
  });
});
